def log_file
  file = File.new('test.log', 'w+')

  # Write log messages immediately to the file.
  file.sync = true
  file
end

def aws_cli_available?
  system("command -v aws >/dev/null 2>&1")
end

def aws_credentials_available?
  system("aws sts get-caller-identity >/dev/null 2>&1")
end

def aws_region_available?
  ENV["AWS_REGION"].to_s != "" || ENV["AWS_DEFAULT_REGION"].to_s != ""
end

def klutch_control_plane_region
  ENV.fetch("A9S_E2E_KLUTCH_REGION", "eu-central-1").to_s.strip
end

def aws_find_vpc_id_by_tags(tags, region:)
  filters = tags.map { |k, v| "Name=tag:#{k},Values=#{v}" }
  args = ["aws", "ec2", "describe-vpcs", "--filters", *filters, "--query", "Vpcs[0].VpcId", "--output", "text"]
  args += ["--region", region] unless region.to_s.strip.empty?
  cmd = Shellwords.join(args)
  logger.info(cmd)

  vpc_id = `#{cmd}`.strip
  return "" if vpc_id.empty? || vpc_id == "None" || vpc_id == "null"

  vpc_id
end

def aws_vpc_exists?(vpc_id, region:)
  args = ["aws", "ec2", "describe-vpcs", "--vpc-ids", vpc_id]
  args += ["--region", region] unless region.to_s.strip.empty?
  cmd = Shellwords.join(args) + " >/dev/null 2>&1"
  logger.info(cmd)
  system(cmd)
end

def aws_verify_vpc_deleted(vpc_id, region:, timeout_seconds: 600, sleep_seconds: 10)
  deadline = Time.now + timeout_seconds
  loop do
    return unless aws_vpc_exists?(vpc_id, region: region)
    if Time.now >= deadline
      raise "VPC #{vpc_id} still exists in region #{region} after #{timeout_seconds}s"
    end
    sleep(sleep_seconds)
  end
end

def aws_verify_vpc_exists(tags, region:, timeout_seconds: 600, sleep_seconds: 10)
  deadline = Time.now + timeout_seconds
  loop do
    vpc_id = aws_find_vpc_id_by_tags(tags, region: region)
    return vpc_id unless vpc_id.empty?
    if Time.now >= deadline
      raise "No VPC found with tags #{tags.inspect} in region #{region} after #{timeout_seconds}s"
    end
    sleep(sleep_seconds)
  end
end

def aws_cognito_user_pool_ids(region:)
  args = ["aws", "cognito-idp", "list-user-pools", "--max-results", "50", "--query", "UserPools[].Id", "--output", "text"]
  args += ["--region", region] unless region.to_s.strip.empty?
  cmd = Shellwords.join(args)
  logger.info(cmd)

  out = `#{cmd}`.strip
  return [] unless $?.success?
  strings = out.split
  strings.reject(&:empty?)
end

def aws_cognito_user_pool_tags(pool_id, region:)
  arn_args = ["aws", "cognito-idp", "describe-user-pool", "--user-pool-id", pool_id, "--query", "UserPool.Arn", "--output", "text"]
  arn_args += ["--region", region] unless region.to_s.strip.empty?
  arn_cmd = Shellwords.join(arn_args)
  logger.info(arn_cmd)

  arn = `#{arn_cmd}`.strip
  return {} unless $?.success? && !arn.empty? && arn != "None" && arn != "null"

  args = ["aws", "cognito-idp", "list-tags-for-resource", "--resource-arn", arn, "--query", "Tags", "--output", "json"]
  args += ["--region", region] unless region.to_s.strip.empty?
  cmd = Shellwords.join(args)
  logger.info(cmd)

  out = `#{cmd}`.strip
  return {} unless $?.success? && !out.empty? && out != "null" && out != "None"

  JSON.parse(out)
rescue JSON::ParserError
  {}
end

def aws_find_cognito_user_pool_id_by_tags(tags, region:)
  aws_cognito_user_pool_ids(region: region).each do |pid|
    pool_tags = aws_cognito_user_pool_tags(pid, region: region)
    next if pool_tags.empty?
    return pid if tags.all? { |k, v| pool_tags[k] == v }
  end
  ""
end

def aws_verify_cognito_user_pool_exists(tags, region:, timeout_seconds: 600, sleep_seconds: 10)
  deadline = Time.now + timeout_seconds
  loop do
    pool_id = aws_find_cognito_user_pool_id_by_tags(tags, region: region)
    return pool_id unless pool_id.empty?
    if Time.now >= deadline
      raise "No Cognito user pool found with tags #{tags.inspect} in region #{region} after #{timeout_seconds}s"
    end
    sleep(sleep_seconds)
  end
end

