def dns_ns_resolvable?(zone)
  zone = zone.to_s.strip
  return false if zone.empty?

  if system("command -v dig >/dev/null 2>&1")
    output = `dig +short NS #{Shellwords.escape(zone)} @8.8.8.8 2>/dev/null`.strip
    return !output.empty?
  end

  if system("command -v nslookup >/dev/null 2>&1")
    output = `nslookup -type=NS #{Shellwords.escape(zone)} 8.8.8.8 2>/dev/null`
    return output.include?("nameserver")
  end

  false
end

def logger
  $logger ||= Logger.new log_file
  $logger.level = Logger::INFO
  $logger
end

def kubectl_create_namespace(namespace)
  cmd = "kubectl create namespace " + namespace
  logger.info(cmd)

  ret = system(cmd)
  raise "Can't create namespace" unless ret
end

def reuse_cluster?
  ENV["A9S_E2E_REUSE_CLUSTER"] == "1"
end

def kubectl_ensure_namespace(namespace)
  cmd = "kubectl get namespace #{namespace} >/dev/null 2>&1 || kubectl create namespace #{namespace}"
  logger.info(cmd)
  ret = system(cmd)
  raise "Can't ensure namespace #{namespace}" unless ret
end

