def kubectl_verify_pg_pods_running(name, namespace, replicas)
  replicas.times do |i|
    pod_name = "#{name}-#{i}"
    cmd = "kubectl get pod #{pod_name} -n #{namespace} -o jsonpath='{.status.phase}' 2>/dev/null"
    logger.info(cmd)
    status = `#{cmd}`.strip
    unless status == "Running"
      raise "Pod #{pod_name} is not running (status=#{status})"
    end
  end
end

def kubectl_pg_master_pod_name(name, namespace)
  label_selector = "a8s.a9s/replication-role=master,a8s.a9s/dsi-group=postgresql.anynines.com,a8s.a9s/dsi-name=#{name}"
  cmd = "kubectl get pods -n #{namespace} -l #{label_selector} -o jsonpath='{.items[0].metadata.name}' 2>/dev/null"
  logger.info(cmd)
  pod = `#{cmd}`.strip
  if pod.empty?
    raise "No master pod found for service instance #{name} in namespace #{namespace}"
  end
  pod
end

def kubectl_psql_select_one(pod_name, namespace, host, username, password, database)
  host_arg = Shellwords.escape(host)
  user_arg = Shellwords.escape(username)
  db_arg = Shellwords.escape(database)
  password_env = Shellwords.escape(password)
  cmd = "kubectl exec -n #{namespace} #{pod_name} -- env PGPASSWORD=#{password_env} psql -h #{host_arg} -U #{user_arg} -d #{db_arg} -tAc 'SELECT 1'"
  logger.info(cmd)
  output = `#{cmd}`.strip
  unless $?.success?
    raise "psql command failed: #{cmd}\n#{output}"
  end
  output
end

def kubectl_verify_pg_pods_not_exists(name, namespace, replicas, timeout_seconds: 120, sleep_seconds: 5)
  deadline = Time.now + timeout_seconds

  loop do
    missing = true
    replicas.times do |i|
      pod_name = "#{name}-#{i}"
      cmd = "kubectl get pod #{pod_name} -n #{namespace} --ignore-not-found -o name 2>/dev/null"
      logger.info(cmd)
      output = `#{cmd}`.strip
      unless output.empty?
        missing = false
        break
      end
    end

    return if missing

    if Time.now >= deadline
      raise "Pods for #{name} still exist in namespace #{namespace} after #{timeout_seconds}s"
    end
    sleep(sleep_seconds)
  end
end

def kubectl_verify_pods_running_by_label(namespace, label_selector)
  cmd = "kubectl get pods -n #{namespace} -l #{label_selector} -o jsonpath='{.items[*].status.phase}' 2>/dev/null"
  logger.info(cmd)
  phases = `#{cmd}`.strip
  unless phases.split.any? { |p| p == "Running" }
    raise "No running pods found in #{namespace} with label #{label_selector} (phases=#{phases})"
  end
end

def kubectl_tenant_ready?(name, namespace:)
  args = ["kubectl", "get", "tenants.klutch.anynines.com", name, "-n", namespace, "-o", "json"]
  cmd = Shellwords.join(args)
  logger.info(cmd)
  out = `#{cmd}`.strip
  return false unless $?.success? && !out.empty?

  data = JSON.parse(out)
  status = data["status"] || {}
  phase = status["phase"].to_s.strip
  return true if phase.casecmp("Ready").zero?

  conditions = status["conditions"]
  if conditions.is_a?(Array)
    conditions.each do |cond|
      next unless cond.is_a?(Hash)
      next unless cond["status"].to_s.strip.casecmp("True").zero?
      type = cond["type"].to_s.strip
      return true if ["Ready", "CredentialsReady", "IdPReady"].any? { |t| t.casecmp(type).zero? }
    end
  end

  oidc = status["oidc"]
  if oidc.is_a?(Hash)
    client_id = oidc["clientID"].to_s.strip
    issuer = oidc["issuer"].to_s.strip
    return true unless client_id.empty? || issuer.empty?
  end

  false
rescue JSON::ParserError
  false
end

def kubectl_wait_for_tenant_ready(name, namespace:, timeout_seconds: 600, sleep_seconds: 10)
  deadline = Time.now + timeout_seconds
  loop do
    return if kubectl_tenant_ready?(name, namespace: namespace)
    if Time.now >= deadline
      raise "Tenant #{namespace}/#{name} did not become ready after #{timeout_seconds}s"
    end
    sleep(sleep_seconds)
  end
end
